import java.util.Scanner;

public class SecureBufferImplementation {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = 10; // Define buffer size

        char[] buffer = new char[bufferSize]; // Buffer with fixed size

        if (userInput.length() > bufferSize) {
            System.out.println("User input exceeds buffer size. Truncating input...");
            userInput = userInput.substring(0, bufferSize); // Truncate user input if it exceeds buffer size
        }

        userInput.getChars(0, userInput.length(), buffer, 0); // Copy user input into buffer

        System.out.println("Buffer content: " + new String(buffer));

        // This code ensures that user input is truncated if it exceeds the buffer size, preventing buffer overflow.
    }
}

